import styled from 'styled-components'

export const StyledNavbar = styled.div`
	background-color: #333;
	color: #fff;
	width: 100%;
	height: 5rem;
	padding: 0px;

	ul {
		padding: 0;
		width: 20%;
		height: 100%;
		list-style-type: none;

	}





`
